import { cn } from "@/lib/utils";

/**
 * "Manta" — the app's pixelated manta-ray mascot. One character, several moods.
 * Each pose is a static, theme-agnostic SVG under /public/mascot (generated by
 * scripts/generate-mascot.mjs). Render it at any size via `className`.
 *
 *   <Mascot pose="sleep" className="size-28" />
 *
 * Decorative by default (aria-hidden). Pass `alt` when it carries meaning.
 */
export type MantaPose = "glide" | "wave" | "cheer" | "sleep" | "dive" | "peek";

export function Mascot({
  pose = "glide",
  className,
  alt,
}: {
  pose?: MantaPose;
  className?: string;
  alt?: string;
}) {
  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src={`/mascot/manta-${pose}.svg`}
      alt={alt ?? ""}
      aria-hidden={alt ? undefined : true}
      draggable={false}
      className={cn("block size-16 select-none", className)}
    />
  );
}
